import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import ThemeToggle from './ThemeToggle';
import {
  Cpu,
  LayoutDashboard,
  TrendingUp,
  LogOut,
  ShieldCheck,
  Terminal,
  User,
  Menu,
  X,
} from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);

  /* 🎯 Triggers theme injection but doesn't assign unused vars */
  useTheme();

  const handleLogout = () => {
    logout();
    setMobileOpen(false);
    navigate('/login');
  };

  const isActive = (path) => location.pathname === path;

  /* ── ⚡ Premium Link Factory ── */
  const linkStyle = (active, accent = false) => ({
    textDecoration: 'none',
    fontWeight: 700,
    fontSize: '10px',
    padding: '0.5rem 1rem',
    borderRadius: '12px',
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
    textTransform: 'uppercase',
    letterSpacing: '0.12em',
    whiteSpace: 'nowrap',
    transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
    cursor: 'pointer',
    ...(accent
      ? {
          background: 'linear-gradient(135deg, var(--accent-secondary), var(--accent-primary))',
          color: '#ffffff',
          border: 'none',
          boxShadow: '0 4px 15px var(--accent-glow)',
        }
      : active
      ? {
          backgroundColor: 'var(--accent-glow)', // Replaced 'accent-muted' with 'accent-glow'
          color: 'var(--accent-primary)',
          border: '1px solid var(--accent-primary)',
        }
      : {
          backgroundColor: 'transparent',
          color: 'var(--text-secondary)',
          border: '1px solid transparent',
        }),
  });

  const navLinks = (
    <>
      {user ? (
        <>
          <Link to="/dashboard" style={linkStyle(isActive('/dashboard'))} onClick={() => setMobileOpen(false)}>
            <LayoutDashboard size={14} /> Dashboard
          </Link>
          <Link to="/generate" style={linkStyle(isActive('/generate'))} onClick={() => setMobileOpen(false)}>
            <TrendingUp size={14} /> Strategy
          </Link>
          <Link to="/profile" style={linkStyle(isActive('/profile'))} onClick={() => setMobileOpen(false)}>
            <User size={14} /> Node
          </Link>
          <button
            onClick={handleLogout}
            style={{
              ...linkStyle(false),
              backgroundColor: 'rgba(239, 68, 68, 0.08)',
              color: '#ef4444',
              border: '1px solid rgba(239, 68, 68, 0.15)',
            }}
          >
            <LogOut size={14} /> <span>Terminate</span>
          </button>
        </>
      ) : (
        <>
          <Link to="/login" style={linkStyle(isActive('/login'))} onClick={() => setMobileOpen(false)}>
            <Terminal size={14} /> Access_Gate
          </Link>
          <Link to="/register" style={linkStyle(false, true)} onClick={() => setMobileOpen(false)}>
            <ShieldCheck size={14} /> Initialize_Node
          </Link>
        </>
      )}
    </>
  );

  return (
    <>
      <header style={{
        position: 'sticky',
        top: 0,
        zIndex: 1000,
        width: '100%',
        padding: '16px 20px',
        display: 'flex',
        justifyContent: 'center',
        /* Removed pointer-events: none to ensure clicks always register */
      }}>
        <nav style={{
          width: '100%',
          maxWidth: '1100px',
          backgroundColor: 'var(--surface-glass)',
          backdropFilter: 'blur(24px)',
          WebkitBackdropFilter: 'blur(24px)',
          border: '1px solid var(--surface-border)',
          borderRadius: '20px',
          boxShadow: 'var(--shadow-elevated)',
          padding: '0.6rem 1.5rem',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
        }}>

          {/* 💎 Institutional Branding */}
          <Link to="/" style={{
            textDecoration: 'none',
            display: 'flex',
            alignItems: 'center',
            gap: '12px',
            color: 'var(--text-primary)',
            fontWeight: 800,
            fontSize: '0.85rem',
            letterSpacing: '0.2em',
            textTransform: 'uppercase',
          }}>
            <div style={{
              width: '36px',
              height: '36px',
              borderRadius: '10px',
              background: 'var(--accent-glow)',
              border: '1px solid var(--accent-primary)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              boxShadow: '0 0 15px var(--accent-glow)',
            }}>
              <Cpu size={18} className="text-[var(--accent-primary)]" />
            </div>
            <span className="hidden sm:inline">Finify AI</span>
          </Link>

          {/* Desktop Hub */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }} className="desktop-nav">
            <ThemeToggle />
            <div style={{ width: '1px', height: '20px', background: 'var(--surface-border)', margin: '0 8px' }} />
            {navLinks}
          </div>

          {/* Mobile Trigger */}
          <button
            onClick={() => setMobileOpen(!mobileOpen)}
            className="mobile-menu-btn"
            style={{
              display: 'none',
              background: 'var(--input-bg)',
              border: '1px solid var(--surface-border)',
              borderRadius: '10px',
              padding: '0.5rem',
              color: 'var(--text-primary)',
              cursor: 'pointer',
            }}
          >
            {mobileOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
        </nav>

        {/* 📱 Mobile Drawer */}
        {mobileOpen && (
          <div style={{
            position: 'absolute',
            top: '85px',
            width: 'calc(100% - 40px)',
            maxWidth: '1100px',
            backgroundColor: 'var(--surface-glass)',
            backdropFilter: 'blur(24px)',
            border: '1px solid var(--surface-border)',
            borderRadius: '20px',
            padding: '1.5rem',
            display: 'flex',
            flexDirection: 'column',
            gap: '12px',
            boxShadow: 'var(--shadow-elevated)',
            zIndex: 999,
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
              <span style={{ fontSize: '10px', fontWeight: 800, color: 'var(--text-muted)', letterSpacing: '0.1em' }}>CONTROL_PANEL</span>
              <ThemeToggle />
            </div>
            {navLinks}
          </div>
        )}
      </header>

      <style>{`
        @media (max-width: 860px) {
          .desktop-nav { display: none !important; }
          .mobile-menu-btn { display: flex !important; }
        }
      `}</style>
    </>
  );
};

export default Navbar;
